static bool IsAlgParamEqual(const BSL_Buffer *lhs, const BSL_Buffer *rhs)
{
    if (lhs->dataLen != rhs->dataLen) {
        return false;
    }
    if (lhs->dataLen == 0) {
        return true;
    }
    return memcmp(lhs->data, rhs->data, lhs->dataLen) == 0;
}
